<template>
  <el-dialog class="recharge-dialog" :visible.sync="rechargeVisible" append-to-body center top="6vh" :before-close="handleClose" width="90%">
    <template v-slot:title>
      <span style="color: white">账户余额：{{ userInfo.coin ? userInfo.coin : 0 }}币</span>
      <div v-if="rechargeHeaderStatus">
        <el-image :src="rechargeHeaderImg" />
      </div>
    </template>
    <el-divider class="divider-class"></el-divider>
    <span class="span-title">选择套餐类型</span>
    <el-radio-group @input="changeRechargeRadio" class="recharge-radio-group" size="small" v-model="rechargeRadio">
      <el-radio-button :label="item.amount" class="recharge-dialog-radio" v-for="item in coinPackageList" :key="item.coin">
        {{ item.amount }}元：{{ item.coin }}{{ coinTitle }}币
      </el-radio-button>
    </el-radio-group>
    <div class="qrcode-box" style="margin-top: 10px">
      <span class="span-title">扫码支付</span>
      <el-image :class="{ 'image-fuzzy': coinRechargeUrlStatus }" :src="coinRechargeUrl" style="margin-top: 10px; margin-bottom: 10px" />
    </div>
  </el-dialog>
</template>
<script>
import { rechargeRecord, getRechargeRecord } from '@/api/main';
export default {
  name: 'RechargeDialog',
  props: {
    coinTitle: {
      type: String,
      default: '土拨鼠'
    }
  },
  data() {
    return {
      rechargeVisible: false,
      userInfo: {},
      rechargeHeaderStatus: null,
      rechargeHeaderImg: null,
      rechargeRadio: null,
      coinPackageList: [],
      // 是否是支付图片初始状态
      coinRechargeUrlStatus: true,
      coinRechargeUrl: require('@/assets/pay-demo.png'),
      rechargeIntervalId: null
    };
  },
  beforeDestroy() {
    this.stopRechargeInterval();
  },
  watch: {
    rechargeVisible(val) {
      if (!val) {
        this.stopRechargeInterval();
      }
    }
  },
  methods: {
    handleOpen(visible, userInfo, status, img, coinPackageList) {
      this.rechargeVisible = visible;
      this.userInfo = userInfo || {};
      this.rechargeHeaderStatus = status;
      this.rechargeHeaderImg = img;
      this.coinPackageList = coinPackageList || [];
    },
    handleClose(done) {
      this.$emit('refreshUserInfo', null);
      this.rechargeVisible = false;
      this.userInfo = {};
      this.stopRechargeInterval();
      done && done();
    },
    changeRechargeRadio(e) {
      let params = {
        amount: e
      };
      rechargeRecord(params).then((response) => {
        this.coinRechargeUrlStatus = false;
        this.coinRechargeUrl = response.data.url;
        this.startRechargeInterval(response.data.id);
      });
    },
    startRechargeInterval(rechargeId) {
      const that = this;
      this.rechargeIntervalId = setInterval(function () {
        console.log('rechargeInterval 定时器运行中', rechargeId);
        getRechargeRecord(rechargeId).then((response) => {
          if (response.data.status === 2) {
            that.stopRechargeInterval(); // 防止定时器重叠
            that.$message.success('充值成功');
            that.$emit('refreshUserInfo', null);
          }
        });
      }, 2000);
    },
    stopRechargeInterval() {
      this.rechargeRadio = null;
      this.coinRechargeUrl = require('@/assets/pay-demo.png');
      this.coinRechargeUrlStatus = true;
      if (this.rechargeIntervalId) {
        clearInterval(this.rechargeIntervalId);
        this.rechargeIntervalId = null;
        console.log('rechargeInterval 定时器关闭');
      }
    }
  }
};
</script>
